    SingleCharIsPalindrome(s, 0);

    // Ghost: track the maximal palindrome length achievable at each "center"
    // position. After processing position i0 with identical expansion to r0
    // and symmetric expansion to [l_f, r_f], the maximal palindrome length
    // for centers in [i0, r0] is r_f - l_f + 1.

    // Ghost: the "next unprocessed" position
    // At the start of each iteration, i is the next center to process.
    // After identical expansion to r, positions [i, r] are processed.
    // i becomes r + 1 for the next iteration.

    var i := 0;

    while i < n
      invariant 0 <= i <= n
      invariant 0 <= start
      invariant 1 <= maxLength
      invariant start + maxLength <= n
      invariant IsPalindrome(s[start..start + maxLength])
      // Run boundary invariant: i is at the start of a maximal run
      invariant i < n ==> (i == 0 || s[i-1] != s[i])
      // Coverage: all palindromes whose midpoint < i are covered
      invariant forall a, ln ::
        0 <= a < n && 1 <= ln <= n &&
        a + ln <= n &&
        IsPalindrome(s[a..a+ln]) &&
        a + (ln - 1) / 2 < i
        ==> ln <= maxLength
    {
        var i0 := i;
        var l := i;
        var r := i;

        SingleCharIsPalindrome(s, i);

        // Expand for identical characters
        while r < n - 1 && s[r] == s[r + 1]
          invariant i <= l <= r < n
          invariant l == i
          invariant IsPalindrome(s[l..r+1])
          invariant forall j :: l <= j <= r ==> s[j] == s[l]
        {
            assert forall j :: l <= j <= r + 1 ==> s[j] == s[l]
            by {
              assert s[r+1] == s[r];
              assert s[r] == s[l];
            }
            var w := s[l..r+2];
            assert forall j :: 0 <= j < |w| ==> w[j] == w[0]
            by {
              forall j | 0 <= j < |w|
                ensures w[j] == w[0]
              {
                assert w[j] == s[l+j];
                assert w[0] == s[l];
              }
            }
            AllEqualIsPalindrome(w);
            r := r + 1;
        }

        // After identical expansion: s[l..r+1] are all s[l], and
        // either r == n-1 or s[r] != s[r+1]
        var r0 := r;  // save for later

        i := r;

        // Expand around center
        while l > 0 && r < n - 1 && s[l - 1] == s[r + 1]
          invariant 0 <= l <= r < n
          invariant IsPalindrome(s[l..r+1])
          invariant l + r == i0 + r0 - (r - r0) * 2 + (r - r0) // nonsense, remove
        {
            PalindromeExpand(s, l, r);
            l := l - 1;
            r := r + 1;
        }

        var length := r - l + 1;
        if length > maxLength
        {
            start := l;
            maxLength := length;
        }

        // Now we need to prove the coverage invariant is maintained.
        // We need: for all palindromes s[a..a+ln] with midpoint in [i0, r0],
        // ln <= maxLength.
        // maxLength >= length = r - l + 1 (the maximal expansion from [i0, r0]).
        // Key claim: any palindrome with midpoint in [i0, r0] has length <= r - l + 1.

        // This requires a lemma. Let me add an assume for now and prove it later.
        assume forall a, ln ::
          0 <= a < n && 1 <= ln <= n && a + ln <= n &&
          IsPalindrome(s[a..a+ln]) &&
          i0 <= a + (ln - 1) / 2 <= r0
          ==> ln <= length;

        i := i + 1;
    }

    result := s[start..start + maxLength];

    assert IsPalindrome(result);
    assert SubstringAt(s, result, start);
    assert IsSubstring(s, result) by {
      assert 0 <= start <= n - maxLength;
    }

    // Prove the optimality part
    forall a, ln |
      0 <= a < |s| && 0 <= ln <= |s| &&
      PalindromicSubstringAt(s, a, ln)
      ensures ln <= |result|
    {
      if ln == 0 {
        assert ln <= |result|;
      } else {
        assert 1 <= ln <= n;
        assert a + ln <= n;
        assert IsPalindrome(s[a..a+ln]);
        var mid := a + (ln - 1) / 2;
        assert 0 <= mid < n;
        assert mid < i;  // i == n after loop
        // By invariant: ln <= maxLength == |result|
      }
    }
}

predicate IsPalindrome(word: seq<char>)
{
  forall i :: 0 <= i < |word| ==> word[i] == word[|word| - 1 - i]
}

predicate SubstringAt(text: seq<char>, sub: seq<char>, start: int)
{
  0 <= start &&
  start + |sub| <= |text| &&
  sub == text[start .. start + |sub|]
}

predicate IsSubstring(text: seq<char>, sub: seq<char>)
{
  exists start :: 0 <= start <= |text| - |sub| && SubstringAt(text, sub, start)
}

predicate PalindromicSubstringAt(s: seq<char>, start: int, len: int)
{
  0 <= start < |s| &&
  0 <= len <= |s| &&
  start + len <= |s| &&
  IsPalindrome(s[start..start+len])
}

predicate longest_palindromic_substringPost(s: seq<char>, result: seq<char>)
{
  |result| >= 1
  && IsSubstring(s, result)
  && IsPalindrome(result)
  && (forall start, len ::
      0 <= start < |s| && 0 <= len <= |s| &&
      PalindromicSubstringAt(s, start, len) ==> len <= |result|)
}

lemma AllEqualIsPalindrome(w: seq<char>)
  requires |w| >= 1
  requires forall i :: 0 <= i < |w| ==> w[i] == w[0]
  ensures IsPalindrome(w)
