lemma PalindromeExpand(s: seq<char>, l: int, r: int)
  requires 0 < l <= r < |s| - 1
  requires IsPalindrome(s[l..r+1])
  requires s[l-1] == s[r+1]
  ensures IsPalindrome(s[l-1..r+2])
{
  var prev := s[l..r+1];
  var next := s[l-1..r+2];
  var m := |next|;
  forall i | 0 <= i < m
    ensures next[i] == next[m - 1 - i]
  {
    if 0 < i < m - 1 {
      assert next[i] == prev[i-1];
      assert next[m-1-i] == prev[m-2-i];
    }
  }
}

