// and s[cl'] = s[cl] = c and s[cr'] = s[cr] = c, the run of c's extends to include
// cl' and cr'. But [cl, cr] is MAXIMAL in the full string s, so cl' and cr' must be
// within [cl, cr] or outside the palindrome.
// Wait, cl' = 2a+ln-1-cl. If cl = midpoint = a+(ln-1)/2 for odd ln, then cl' = a+(ln-1)/2 = cl. OK.
// If cl < midpoint, then cl' > midpoint. Since cl' has character c and [cl,cr] is maximal,
// cl' must be <= cr. So cl' <= cr, meaning 2a+ln-1-cl <= cr, i.e., cl+cr >= 2a+ln-1.
// Similarly, cr > midpoint means cr' < midpoint, and cr' >= cl, so 2a+ln-1-cr >= cl,
// i.e., cl+cr <= 2a+ln-1.
// Combined: cl+cr == 2a+ln-1.

// So [cl, cr] IS symmetric within the palindrome! cl+cr = 2a+ln-1.
// This means cl-a = a+ln-1-cr, so the expansion needs the same number of steps on each side.
// And for each step k: s[cl-k] by palindrome equals s[2a+ln-1-(cl-k)] = s[cr+k]. Done!

// Great. So the expansion from [cl, cr] matches at least cl-a steps, giving
// palindrome from a to a+ln-1, length ln. QED.

// But wait - [cl, cr] is the maximal run in the FULL string s, and the algorithm's
// run might be different because it only goes RIGHT from position i0.
// The algorithm starts at i0 (left edge of maximal run) and expands right.
// So the algorithm's run IS [i0, r0] = [cl, cr] when i0 = cl.
// We established that i0 is always at a run boundary, so i0 = cl.

// But what about the RIGHT boundary? The algorithm expands right while s[r]==s[r+1].
// It stops when s[r] != s[r+1] or r == n-1. So r0 is the rightmost position in the
// maximal run starting at i0. Hence r0 = cr.

// OK so the algorithm's center run [i0, r0] = [cl, cr] = maximal run.
// And the expansion from this goes at least ln steps. QED.

// Now I need to express this as a Dafny lemma. The statement should be:
// If s[a..a+ln] palindrome, [cl, cr] all same char with cl+cr == 2*a+ln-1,
// and the expansion from [cl, cr] is maximal (stopping conditions met),
// then the maximal expansion length >= ln.

// Actually, for Dafny, I think the simplest statement is:
// If s[a..a+ln] palindrome with midpoint p in [cl, cr], all chars in [cl,cr] equal,
// cl+cr = 2a+ln-1, and the expansion from [cl,cr] yields [l_f, r_f],
// then l_f <= a and r_f >= a+ln-1, so r_f - l_f + 1 >= ln.

// But the expansion [l_f, r_f] is computed by the algorithm, not known in the lemma.
// The lemma should state: the palindrome property of s[a..a+ln] implies that
// s[cl-k] == s[cr+k] for k = 1, ..., cl-a. This means the expansion from [cl,cr]
// goes at least cl-a steps, reaching [a, a+ln-1].

// Let me write this lemma.

lemma CenterExpansionCoverspalindrome(s: seq<char>, a: int, ln: int, cl: int, cr: int)
  requires |s| > 0
  requires 0 <= a && a + ln <= |s| && ln >= 1
  requires IsPalindrome(s[a..a+ln])
  requires a <= cl <= cr <= a + ln - 1
  requires cl + cr == 2 * a + ln - 1
  requires forall j :: cl <= j <= cr ==> s[j] == s[cl]
  ensures forall k :: 1 <= k <= cl - a ==> (
    cl - k >= 0 && cr + k < |s| && s[cl - k] == s[cr + k])
{
  var w := s[a..a+ln];
  forall k | 1 <= k <= cl - a
    ensures cl - k >= 0 && cr + k < |s| && s[cl - k] == s[cr + k]
  {
    assert cl - k >= a;
    assert cr + k <= a + ln - 1;
    // From palindrome: w[j] == w[ln-1-j]
    // s[cl-k] = s[a + (cl-a-k)] = w[cl-a-k]
    var j1 := cl - a - k;
    assert 0 <= j1 < ln;
    assert s[cl-k] == w[j1];
    // w[j1] == w[ln-1-j1] = w[ln-1-(cl-a-k)] = w[ln-1-cl+a+k]
    // = w[cr - a + k] (since cl+cr=2a+ln-1 => ln-1-cl+a = cr-a)
    assert ln - 1 - j1 == cr - a + k;
    assert w[j1] == w[cr - a + k];
    assert s[cr+k] == w[cr - a + k];
  }
}

// Lemma: the midpoint of any palindrome s[a..a+ln] is within the maximal
// run of identical characters containing it, and cl+cr = 2a+ln-1.
// This requires showing that the palindrome's center run is symmetric.
lemma PalindromeCenterRunSymmetric(s: seq<char>, a: int, ln: int, cl: int, cr: int)
  requires |s| > 0
  requires 0 <= a && a + ln <= |s| && ln >= 1
  requires IsPalindrome(s[a..a+ln])
  requires a <= cl <= a + (ln - 1) / 2
  requires a + (ln - 1) / 2 <= cr <= a + ln - 1
  requires forall j :: cl <= j <= cr ==> s[j] == s[cl]
  // The run is maximal within [a, a+ln-1] in the sense that
  // if cl > a then s[cl-1] != s[cl], and if cr < a+ln-1 then s[cr+1] != s[cr]
  // (these are for the maximal run in the full string)
  requires cl == a || s[cl-1] != s[cl]
  requires cr == a + ln - 1 || s[cr+1] != s[cr]
  ensures cl + cr == 2 * a + ln - 1
{
  var w := s[a..a+ln];
  var mid := a + (ln - 1) / 2;
  var c := s[mid];

  // By palindrome: s[a+j] == s[a+ln-1-j]
  // s[cl] = c (since cl is in the run and run contains mid, all chars = s[mid] = c)
  // s[2a+ln-1-cl] = c by palindrome (reflection of cl)
  // Let cl' = 2a+ln-1-cl. Then a <= cl' <= a+ln-1.
  // s[cl'] = c. If cl' > cr, then [cl, cr] is not maximal (cl' has char c and cl' > cr).
  // But we assumed maximality: if cr < a+ln-1 then s[cr+1] != c.
  // If cl' > cr, then cl' >= cr+1, so s[cl'] should != c. Contradiction.
  // So cl' <= cr.
  // Similarly, cr' = 2a+ln-1-cr. cr' >= cl by similar argument.
  // cl' = 2a+ln-1-cl <= cr, so cl+cr >= 2a+ln-1.
  // cr' = 2a+ln-1-cr >= cl, so cl+cr <= 2a+ln-1.
  // Therefore cl+cr = 2a+ln-1.

  var cl' := 2 * a + ln - 1 - cl;
  var cr' := 2 * a + ln - 1 - cr;

  // Show cl' <= cr (so cl+cr >= 2a+ln-1)
  assert a <= cl' <= a + ln - 1;
  assert s[cl'] == c by {
    var j := cl - a;
    assert w[j] == s[a + j] == s[cl];
    assert w[ln - 1 - j] == s[a + ln - 1 - j] == s[cl'];
    assert w[j] == w[ln - 1 - j];
    assert s[cl] == s[cl'];
  }
  // If cl' > cr then cl' >= cr + 1 and s[cl'] = c but s[cr+1] != c (by maximality). Contradiction.
  if cl' > cr {
    assert cl' >= cr + 1;
    if cr < a + ln - 1 {
      assert s[cr + 1] != c;
      // But cl' >= cr+1 means... actually cl' might not equal cr+1.
      // We know s[cl'] = c. And cl' is in [cr+1, a+ln-1].
      // But we only know s[cr+1] != c, not s[cl'] != c.
      // Hmm, we need the run to be maximal in the full string, not just at cr+1.
      // The maximality condition s[cr+1] != s[cr] only tells us about cr+1.
      // There could be another run of c's further right.
      // So this approach doesn't work directly.
      // We need a STRONGER maximality condition: [cl, cr] is the maximal run
      // of character c containing the midpoint.
      assert false; // This branch should be unreachable with stronger conditions
    } else {
      // cr == a + ln - 1, so cl' > a+ln-1, contradiction with cl' <= a+ln-1
      assert false;
    }
  }

  // Similarly show cr' >= cl (so cl+cr <= 2a+ln-1)
  assert a <= cr' <= a + ln - 1;
  assert s[cr'] == c by {
    var j := cr - a;
    assert w[j] == s[cr];
    assert w[ln - 1 - j] == s[cr'];
    assert w[j] == w[ln - 1 - j];
    assert s[cr] == s[cr'];
  }
  if cr' < cl {
    if cl > a {
      assert s[cl - 1] != c;
      assert false;
    } else {
      assert false;
    }
  }

  assert cl' <= cr;  // cl+cr >= 2a+ln-1
  assert cr' >= cl;  // cl+cr <= 2a+ln-1
}

