// Helper function: the leftmost position of the maximal run of s[p] containing position p
function {:opaque} RunStart(s: seq<char>, p: int): int
  requires 0 <= p < |s|
  ensures 0 <= RunStart(s, p) <= p
  ensures forall j :: RunStart(s, p) <= j <= p ==> s[j] == s[p]
  ensures RunStart(s, p) == 0 || s[RunStart(s, p) - 1] != s[p]
{
  if p == 0 || s[p-1] != s[p] then p
  else RunStart(s, p-1)
}

// Helper: the rightmost position of the maximal run of s[p] containing position p
function {:opaque} RunEnd(s: seq<char>, p: int): int
  requires 0 <= p < |s|
  ensures p <= RunEnd(s, p) < |s|
  ensures forall j :: p <= j <= RunEnd(s, p) ==> s[j] == s[p]
  ensures RunEnd(s, p) == |s| - 1 || s[RunEnd(s, p) + 1] != s[p]
{
  if p == |s| - 1 || s[p+1] != s[p] then p
  else RunEnd(s, p+1)
}

// The identical-chars expansion from position i finds RunEnd(s, i)
lemma IdenticalExpansionFindsRunEnd(s: seq<char>, i: int, r: int)
  requires 0 <= i < |s|
  requires i <= r < |s|
  requires forall j :: i <= j <= r ==> s[j] == s[i]
  requires r == |s| - 1 || s[r] != s[r+1]
  ensures r == RunEnd(s, i)
{
  reveal RunEnd();
  if i == r {
    if i == |s| - 1 {
    } else {
      assert s[i] != s[i+1];
    }
  } else {
    // r > i, so s[i] == s[i+1]
    assert s[i] == s[i+1];
    // RunEnd(s, i) == RunEnd(s, i+1) when s[i] == s[i+1]
    IdenticalExpansionFindsRunEnd(s, i+1, r);
  }
}

// Key lemma: for any palindrome s[a..a+ln], the expansion from the maximal run
// containing its midpoint covers the entire palindrome.
// Specifically: if p is the midpoint and [rs, re] is the maximal run of s[p]
// containing p, then s[rs-k] == s[re+k] for k = 1, ..., rs - a.
lemma {:induction false} PalindromeCoveredByCenter(s: seq<char>, a: int, ln: int)
  requires |s| > 0
  requires 0 <= a && a + ln <= |s| && ln >= 1
  requires IsPalindrome(s[a..a+ln])
  ensures var p := a + (ln - 1) / 2;
          var rs := RunStart(s, p);
          var re := RunEnd(s, p);
          rs >= a && re <= a + ln - 1 &&
          (forall k :: 1 <= k <= rs - a ==> s[rs - k] == s[re + k])
{
  reveal RunStart();
  reveal RunEnd();
  var w := s[a..a+ln];
  var p := a + (ln - 1) / 2;
  var rs := RunStart(s, p);
  var re := RunEnd(s, p);
  var c := s[p];

  // First show rs >= a
  // By induction / definition of RunStart: all positions from rs to p have char c.
  // If rs < a, then s[rs] = c. But rs < a means rs is outside the palindrome.
  // We can't directly conclude anything... we need the run to start within [a, a+ln-1].
  // Actually, RunStart gives the leftmost position in the FULL string with char c in the run.
  // It could be < a. Let's handle this.
  // If rs < a, that's fine - the expansion from [rs, re] covers an even wider range.
  // Actually no, we need rs >= a for the expansion steps to be within bounds.
  // Hmm, but rs < a means the run starts before the palindrome, which means
  // the expansion from [rs, re] would reach even further left than a.
  // So the palindrome [a, a+ln-1] is definitely covered.
  // But the postcondition says rs >= a... let me reconsider.
  // If rs < a, then the center run starts before the palindrome.
  // The expansion from [rs, re] would check s[rs-1] vs s[re+1], etc.
  // It doesn't directly tell us it covers [a, a+ln-1].
  // Actually it does: the expansion goes as far as possible, and since
  // s[a..a+ln] is a palindrome, it can go at least to a on the left.
  // But if rs < a, then it starts even further left, so it definitely reaches a.

  // Wait, I need to rethink. The expansion from [rs, re] checks s[rs-1] == s[re+1],
  // s[rs-2] == s[re+2], etc. It goes as far as it can. Since s[a..a+ln] is a palindrome,
  // the positions within it are symmetric. But positions outside [a, a+ln-1] might not match.

  // So the expansion from [rs, re] might stop before reaching a (on the left)
  // if re > a+ln-1 and the expansion hits a mismatch outside the palindrome on the right.

  // Hmm, but can rs < a? If rs < a, then s[rs] = c = s[p].
  // All positions from rs to p have character c.
  // In particular, s[a-1] = c (if rs < a, then rs <= a-1 < p, so s[a-1] = c).
  // But s[a] might or might not be c.
  // If s[a] = c, then by palindrome, s[a+ln-1] = c.
  // And s[a-1] = c doesn't violate anything.
  // So rs < a is possible.

  // Similarly re > a+ln-1 is possible.

  // OK so my approach of using [rs, re] as the center for expansion doesn't
  // directly work because [rs, re] might extend beyond the palindrome.

  // Let me reconsider. The algorithm processes the run starting at rs (= i0),
  // expands to re (= r0), then expands symmetrically. The symmetric expansion
  // checks s[rs-1] == s[re+1], etc. Since s[a..a+ln] is a palindrome:
  // For the expansion to cover [a, a+ln-1], we need:
  // s[rs-k] == s[re+k] for k = 1, ..., rs-a (if rs >= a) or more generally,
  // the expansion goes at least min(rs, ...) steps.

  // The problem is: if rs < a, the expansion starts from [rs, re] which is
  // WIDER than the palindrome's center. This means the expansion might
  // actually find something LONGER than [a, a+ln-1]. But it could also stop
  // sooner because positions outside [a, a+ln-1] might mismatch.

  // Example: s = "dacbd", palindrome "c" at [2,2], midpoint=2, run [2,2].
  // Expansion: s[1]='a', s[3]='b', mismatch. Found "c" of length 1. Fine.

  // Example: s = "daccbd", palindrome "cc" at [2,3], midpoint=2, run [2,3].
  // Expansion: s[1]='a', s[4]='b', mismatch. Found "cc" of length 2. Fine.

  // Example where rs < a: s = "xccxccx". Palindrome "xccx" at [0,3], ln=4, mid=1.
  // s[1]='c', run of 'c' is [1,2]. rs=1, re=2. rs >= a=0? rs=1 > 0=a. OK.
  // Hmm, I need a case where rs < a.
  // s = "ccacc". Palindrome "acc" at [2,4]? "acc" is not palindrome.
  // s = "ccacca". Palindrome at... hmm hard to construct.
  // Actually, for palindrome s[a..a+ln], its midpoint has some character c.
  // The maximal run of c containing the midpoint can't extend below a because:
  // If it did, s[a-1] = c. But s[a] is the mirror of s[a+ln-1] in the palindrome.
  // s[a] might not be c (if a is far from the midpoint).
  // But s[a-1] = c doesn't mean the run goes below a - it means the run of c's
  // in the full string goes below a.
