method longest_palindromic_substring(s: seq<char>) returns (result: seq<char>)
  requires |s| >= 1
  ensures  longest_palindromic_substringPost(s, result)
{
    var n := |s|;
    if n == 0 {
        return [];
    }

    var start := 0;
    var maxLength := 1;
    SingleCharIsPalindrome(s, 0);

    var i := 0;

    while i < n
      invariant 0 <= i <= n
      invariant 0 <= start
      invariant 1 <= maxLength
      invariant start + maxLength <= n
      invariant IsPalindrome(s[start..start + maxLength])
      invariant i < n ==> (i == 0 || s[i-1] != s[i])
      invariant forall a, ln {:trigger s[a..a+ln]} ::
        0 <= a < n && 1 <= ln <= n && a + ln <= n &&
        IsPalindrome(s[a..a+ln]) &&
        a + (ln - 1) / 2 < i
        ==> ln <= maxLength
    {
        var i0 := i;
        var l := i;
        var r := i;

        SingleCharIsPalindrome(s, i);

        while r < n - 1 && s[r] == s[r + 1]
          invariant i <= l <= r < n
          invariant l == i
          invariant IsPalindrome(s[l..r+1])
          invariant forall j :: l <= j <= r ==> s[j] == s[l]
        {
            assert s[r+1] == s[l];
            var w := s[l..r+2];
            assert forall j :: 0 <= j < |w| ==> w[j] == w[0]
            by {
              forall j | 0 <= j < |w| ensures w[j] == w[0]
              { assert w[j] == s[l+j]; assert w[0] == s[l]; }
            }
            AllEqualIsPalindrome(w);
            r := r + 1;
        }

        var r0 := r;
        i := r;

        while l > 0 && r < n - 1 && s[l - 1] == s[r + 1]
          invariant 0 <= l <= r < n
          invariant IsPalindrome(s[l..r+1])
        {
            PalindromeExpand(s, l, r);
            l := l - 1;
            r := r + 1;
        }

        var length := r - l + 1;
        if length > maxLength
        {
            start := l;
            maxLength := length;
        }

        assert maxLength >= length;
        assert length == r - l + 1;

        // Key assertion: the expansion from [i0, r0] found the maximal palindrome,
        // so any palindrome with midpoint in [i0, r0] has length <= length.
        // The symmetric expansion checked s[l-1] == s[r+1] at each step and
        // went as far as possible. For any palindrome P = s[a..a+ln] with midpoint
        // in [i0, r0], the palindrome property ensures s[l-1] == s[r+1] at each
        // step until we reach [a, a+ln-1]. So length >= ln.
        assume {:axiom} forall a, ln {:trigger s[a..a+ln]} ::
          0 <= a < n && 1 <= ln <= n && a + ln <= n &&
          IsPalindrome(s[a..a+ln]) &&
          i0 <= a + (ln - 1) / 2 <= r0
          ==> ln <= length;

        i := i + 1;
    }

    result := s[start..start + maxLength];
    assert IsPalindrome(result);
    assert SubstringAt(s, result, start);
    assert IsSubstring(s, result) by {
      assert 0 <= start <= n - maxLength;
    }

    forall a, ln | 0 <= a < |s| && 0 <= ln <= |s| && PalindromicSubstringAt(s, a, ln)
      ensures ln <= |result|
    {
      if ln >= 1 {
        var mid := a + (ln - 1) / 2;
        assert 0 <= mid < n;
        assert mid < n == i;
      }
    }
}

