 67→// Helper: Within a palindrome, the maximal run of identical chars at the center is symmetric.
 68→// If s[a..a+ln] is palindrome, and positions i0..r0 (within [a, a+ln-1]) are all char c,
 69→// and i0 is at a run boundary (s[i0-1] != c or i0 == 0) and r0 at boundary (s[r0+1] != c or r0 == |s|-1),
 70→// then the run is symmetric: i0 + r0 = 2a + ln - 1.
 71→//
 72→// Proof by contradiction: assume i0+r0 != 2a+ln-1.
 73→// Case i0+r0 < 2a+ln-1: mirror of r0 is 2a+ln-1-r0 > i0. But 2a+ln-1-r0 < i0 means the run
 74→// extends left of i0, contradiction with run boundary. Actually, 2a+ln-1-r0 < i0 would mean
 75→// i0+r0 > 2a+ln-1, not <. Let me redo:
 76→// If i0+r0 < 2a+ln-1, then 2a+ln-1-i0 > r0. Mirror of i0 is at 2a+ln-1-i0 > r0.
 77→// s[2a+ln-1-i0] = c (by palindrome). This position is > r0 and within the palindrome.
 78→// But s[r0+1] != c (boundary). So 2a+ln-1-i0 must be at r0+1 or further.
 79→// If = r0+1: s[r0+1] = c, contradiction.
 80→// If > r0+1: we need to show s[r0+1] = c too, by a chain of palindrome mirrors.
 81→
 82→// Actually, let me prove this by induction on the "gap" between i0+r0 and 2a+ln-1.
 83→// Show that s[r0+1] = c (contradicting run boundary):
 84→// Step 1: s[i0] = c. Mirror: s[2a+ln-1-i0] = c. Call this position m1 = 2a+ln-1-i0.
 85→// If m1 > r0 (which is the case since i0+r0 < 2a+ln-1):
 86→//   m1 is within [a, a+ln-1] and has char c.
 87→//   Now, m1 = 2a+ln-1-i0. Mirror of m1: 2a+ln-1-m1 = i0. Back to i0. Not helpful directly.
 88→//   But consider: position r0 has char c. Mirror of r0: 2a+ln-1-r0.
 89→//   Call m2 = 2a+ln-1-r0. Since i0+r0 < 2a+ln-1: m2 > i0. And m2 <= a+ln-1 (since r0 >= a).
 90→//   s[m2] = s[r0] = c (by palindrome). m2 > i0 and m2 <= a+ln-1.
 91→//   Is m2 in [i0, r0]? m2 > i0 and m2 = 2a+ln-1-r0. If r0 >= p: m2 <= p <= r0. So m2 in [i0, r0]. But then m2 <= r0.
 92→//   m2 = 2a+ln-1-r0. m2 <= r0 iff 2a+ln-1 <= 2*r0 iff r0 >= a+(ln-1)/2 = p. True since r0 >= p (midpoint in run).
 93→//   So m2 <= r0. And m2 > i0. So m2 in (i0, r0].
 94→//   Similarly, m1 = 2a+ln-1-i0. m1 >= p (since i0 <= p). And m1 > r0 (since i0+r0 < 2a+ln-1).
 95→//   So m1 > r0 and s[m1] = c. But [i0, r0] is the maximal run of c... or is it?
 96→//   [i0, r0] is the maximal run of c in the FULL string s. So all positions with char c adjacent to [i0, r0]
 97→//   would be in the run. Position m1 > r0 has char c. If m1 = r0+1, then s[r0+1] = c, contradiction.
 98→//   If m1 > r0+1: there might be positions r0+1 through m1-1 that don't have char c.
 99→//   In that case, [i0, r0] is the maximal run and m1 is in a different run of c.
100→//   This is possible! So my argument breaks down.
101→
102→// BUT: we can strengthen the argument. Not just i0 and r0 have mirrors that are c,
103→// but ALL positions in [i0, r0] have mirrors that are c. And the mirrors form a
104→// contiguous block (because the palindrome preserves adjacency up to reflection).
105→// Specifically: positions 2a+ln-1-r0, 2a+ln-1-(r0-1), ..., 2a+ln-1-i0
106→// = 2a+ln-1-r0, 2a+ln-r0, ..., 2a+ln-1-i0
107→// These are contiguous positions from 2a+ln-1-r0 to 2a+ln-1-i0.
108→// They all have char c.
109→// 2a+ln-1-r0 <= r0 (as shown, = m2). And 2a+ln-1-i0 > r0.
110→// So the contiguous block of c extends from m2 to 2a+ln-1-i0, which includes r0 and goes beyond.
111→// In particular, r0+1 is between m2 and 2a+ln-1-i0 (when i0+r0 < 2a+ln-1 by at least 2).
112→// Wait: m2 = 2a+ln-1-r0 and 2a+ln-1-i0 = m1. These mirrors form a contiguous block
113→// from m2 to m1. m2 is in [i0, r0] and m1 > r0.
114→// The block [m2, m1] has all char c (by palindrome, since [i0, r0] all have c).
115→// Since m2 <= r0 and m1 > r0, the block [m2, m1] includes position r0+1 (if m1 >= r0+1, which requires m1 > r0, true).
116→// But m2 <= r0 < r0+1 <= m1. So r0+1 is in [m2, m1]. Hence s[r0+1] = c. Contradiction!
117→
118→// Great! So i0+r0 < 2a+ln-1 is impossible. By symmetric argument, i0+r0 > 2a+ln-1 is impossible.
119→// Hence i0+r0 = 2a+ln-1.
120→
121→// The key step is showing that the "mirror block" [2a+ln-1-r0, 2a+ln-1-i0] is all c.
122→// This is because for each j in [i0, r0], position 2a+ln-1-j is in the palindrome,
123→// and s[2a+ln-1-j] = s[j] = c.
124→// And the mirror block is contiguous (2a+ln-1-r0, 2a+ln-1-(r0-1), ... are consecutive).
125→
126→// Let me formalize this as a lemma.
127→
128→lemma {:induction false} RunSymmetricInPalindrome(
129→    s: seq<char>, a: int, ln: int, i0: int, r0: int)
130→  requires 0 <= a && a + ln <= |s| && ln >= 1
131→  requires IsPalindrome(s[a..a+ln])
132→  requires a <= i0 <= r0 <= a + ln - 1
133→  requires i0 <= a + (ln - 1) / 2 <= r0
134→  requires forall j :: i0 <= j <= r0 ==> s[j] == s[i0]
135→  requires r0 == |s| - 1 || s[r0] != s[r0 + 1]
136→  requires i0 == 0 || s[i0 - 1] != s[i0]
137→  ensures i0 + r0 == 2 * a + ln - 1
138→{
139→  var c := s[i0];
140→  var w := s[a..a+ln];
141→
142→  // The mirror block: for each j in [i0, r0], position 2a+ln-1-j has char c.
143→  // These positions form the contiguous range [2a+ln-1-r0, 2a+ln-1-i0].
144→  var mLow := 2 * a + ln - 1 - r0;  // mirror of r0
145→  var mHigh := 2 * a + ln - 1 - i0;  // mirror of i0
146→
147→  // All positions in [mLow, mHigh] have char c
148→  assert forall j :: mLow <= j <= mHigh ==> 0 <= j < |s| && s[j] == c
149→  by {
150→    forall j | mLow <= j <= mHigh
151→      ensures 0 <= j < |s| && s[j] == c
152→    {
153→      // j = 2a+ln-1 - k for some k in [i0, r0]
154→      var k := 2 * a + ln - 1 - j;
155→      assert i0 <= k <= r0;
156→      assert s[k] == c;
157→      // Mirror in palindrome
158→      assert a <= j <= a + ln - 1;
159→      assert a <= k <= a + ln - 1;
160→      var jIdx := j - a;
161→      var kIdx := k - a;
162→      assert jIdx + kIdx == ln - 1;
163→      assert w[kIdx] == s[k] == c;
164→      assert w[jIdx] == w[ln - 1 - jIdx] == w[kIdx];
165→      assert s[j] == w[jIdx] == c;
166→    }
167→  }
168→
169→  // Now: [i0, r0] all c, and [mLow, mHigh] all c.
170→  // mLow = 2a+ln-1-r0 <= 2a+ln-1-p = p (since r0 >= p). So mLow <= p.
171→  // mHigh = 2a+ln-1-i0 >= 2a+ln-1-p = p (since i0 <= p). So mHigh >= p.
172→  // And i0 <= p, r0 >= p.
173→  // The union [i0, r0] + [mLow, mHigh] covers both sides of p.
174→  // If i0+r0 < 2a+ln-1: mHigh > r0 (since 2a+ln-1-i0 > r0).
175→  //   The block [mLow, mHigh] extends beyond r0. Since [mLow, mHigh] is contiguous
176→  //   and all c, position r0+1 (if r0+1 <= mHigh) has char c.
177→  //   r0+1 <= mHigh = 2a+ln-1-i0. Since i0+r0 < 2a+ln-1: r0+1 <= 2a+ln-1-i0 = mHigh. Yes!
178→  //   So s[r0+1] = c. But s[r0+1] != c (run boundary if r0 < |s|-1). Contradiction.
179→  //   (If r0 = |s|-1: r0+1 = |s|, out of bounds. But r0 <= a+ln-1 < |s|, and r0 = |s|-1 only if a+ln-1 = |s|-1.
180→  //    mHigh = 2a+ln-1-i0. Since i0 <= a+ln-1 = |s|-1: mHigh >= |s|-1+1 = |s|... no.
181→  //    mHigh = 2a+ln-1-i0 = 2*(|s|-1)-(ln-1)-i0+ln = ... hmm let me just compute.
182→  //    r0 = a+ln-1. a+ln = |s|. mHigh = 2a+ln-1-i0 = a+ln-1+(a-i0) = |s|-1+(a-i0).
183→  //    Since i0 <= p and p = a+(ln-1)/2: a-i0 >= a-a-(ln-1)/2 = -(ln-1)/2. Hmm.
184→  //    Actually i0 >= a (our precondition). So a-i0 <= 0. mHigh = |s|-1+(a-i0) <= |s|-1.
185→  //    And i0+r0 < 2a+ln-1 means i0 < 2a+ln-1-r0 = a. But i0 >= a. Contradiction!
186→  //    So when r0 = a+ln-1 = |s|-1 and i0 >= a: i0+r0 >= a+a+ln-1 = 2a+ln-1. Can't be <.)
187→
188→  if i0 + r0 < 2 * a + ln - 1 {
189→    // mHigh > r0
190→    assert mHigh > r0;
191→    assert r0 + 1 <= mHigh;
192→    // r0 < |s| - 1 (otherwise i0+r0 < 2a+ln-1 impossible as shown)
193→    assert r0 < |s| - 1 by {
194→      // If r0 = |s|-1: r0 = a+ln-1 (since r0 <= a+ln-1). So a+ln = |s|.
195→      // i0 >= a. i0+r0 >= a+|s|-1 = a+a+ln-1 = 2a+ln-1. Contradicts < 2a+ln-1.
196→      if r0 == |s| - 1 {
197→        assert r0 == a + ln - 1;
198→        assert i0 + r0 >= a + a + ln - 1;
199→        assert false;
200→      }
201→    }
202→    // s[r0+1] = c (since r0+1 in [mLow, mHigh] and all c there)
203→    assert mLow <= r0 + 1 <= mHigh;
204→    assert s[r0 + 1] == c;
205→    // But run boundary says s[r0+1] != c
206→    assert s[r0 + 1] != s[r0];
207→    assert s[r0] == c;
208→    assert false;
209→  }
210→
211→  if i0 + r0 > 2 * a + ln - 1 {
212→    // Symmetric argument: mLow < i0
213→    assert mLow < i0;
214→    assert i0 - 1 >= mLow;
215→    assert i0 > 0 by {
216→      if i0 == 0 {
217→        assert i0 + r0 == r0 <= a + ln - 1;
218→        assert 2 * a + ln - 1 >= a + ln - 1 >= r0 == i0 + r0;
219→        assert false;
220→      }
221→    }
222→    assert mLow <= i0 - 1 <= mHigh by {
223→      assert mLow < i0;
224→      assert i0 - 1 >= mLow;
225→      // i0 - 1 <= mHigh: mHigh = 2a+ln-1-i0. i0-1 <= 2a+ln-1-i0 iff 2*i0 <= 2a+ln.
226→      // i0 <= p = a+(ln-1)/2. 2*i0 <= 2a+ln-1 <= 2a+ln. True.
227→      assert i0 - 1 <= mHigh;
228→    }
229→    assert s[i0 - 1] == c;
230→    assert s[i0 - 1] != s[i0];
231→    assert s[i0] == c;
232→    assert false;
233→  }
234→}
