236→// If palindrome s[a..a+ln] and [i0,r0] is symmetric center (i0+r0=2a+ln-1, all same char),
237→// then s[i0-k] == s[r0+k] for each expansion step k.
238→lemma {:induction false} SymmetricExpansionStep(
239→    s: seq<char>, a: int, ln: int, i0: int, r0: int, k: int)
240→  requires 0 <= a && a + ln <= |s| && ln >= 1
241→  requires IsPalindrome(s[a..a+ln])
242→  requires a <= i0 <= r0 <= a + ln - 1
243→  requires i0 + r0 == 2 * a + ln - 1
244→  requires 1 <= k <= i0 - a
245→  ensures 0 <= i0 - k && r0 + k < |s| && s[i0 - k] == s[r0 + k]
246→{
247→  assert i0 - k >= a >= 0;
248→  assert r0 + k <= a + ln - 1 < |s|;
249→
250→  var w := s[a..a+ln];
251→  var j := i0 - a - k;
252→  assert 0 <= j;
253→  assert j < ln by { assert i0 <= a + ln - 1; }
254→
255→  assert s[i0 - k] == s[a + j] == w[j];
256→
257→  var j2 := r0 - a + k;
258→  assert j2 == ln - 1 - j;
259→  assert 0 <= j2 < ln;
260→  assert s[r0 + k] == s[a + j2] == w[j2];
261→
262→  assert w[j] == w[ln - 1 - j];
263→}
264→
265→// When the run [i0, r0] starts before the palindrome (i0 < a), the run extends
266→// past the right end of the palindrome too.
267→lemma {:induction false} RunExtendsBeyondPalindrome(
268→    s: seq<char>, a: int, ln: int, i0: int, r0: int)
269→  requires 0 <= i0 < a
270→  requires a + ln <= |s| && ln >= 1
271→  requires IsPalindrome(s[a..a+ln])
272→  requires 0 <= i0 <= r0 < |s|
273→  requires i0 <= a + (ln - 1) / 2 <= r0
274→  requires forall j :: i0 <= j <= r0 ==> s[j] == s[i0]
275→  requires r0 == |s| - 1 || s[r0] != s[r0 + 1]
276→  requires i0 == 0 || s[i0 - 1] != s[i0]
277→  ensures r0 >= a + ln - 1
278→{
279→  var c := s[i0];
280→  var w := s[a..a+ln];
281→  var p := a + (ln - 1) / 2;
282→
283→  // All positions from i0 to r0 are c. Since i0 < a <= p <= r0, positions [a, r0] are all c.
284→  // In particular, s[a] = c.
285→  assert s[a] == c;
286→
287→  // Suppose r0 < a+ln-1. We'll derive a contradiction.
288→  if r0 < a + ln - 1 {
289→    // Palindrome mirrors: for each position j in [a, r0], s[j] = c,
290→    // and its mirror 2a+ln-1-j also has char c.
291→    // Mirror range: [2a+ln-1-r0, 2a+ln-1-a] = [2a+ln-1-r0, a+ln-1].
292→    // 2a+ln-1-r0 > a (since r0 < a+ln-1 means 2a+ln-1-r0 > a).
293→    // Actually 2a+ln-1-r0 = a + (a+ln-1-r0). Since r0 < a+ln-1: a+ln-1-r0 >= 1.
294→    // So 2a+ln-1-r0 >= a+1.
295→    var mLow := 2 * a + ln - 1 - r0;
296→    assert mLow >= a + 1;
297→    assert mLow <= a + ln - 1;
298→
299→    // All positions in [mLow, a+ln-1] have char c (mirrors of [a, r0])
300→    assert forall j :: mLow <= j <= a + ln - 1 ==> s[j] == c
301→    by {
302→      forall j | mLow <= j <= a + ln - 1
303→        ensures s[j] == c
304→      {
305→        var k := 2 * a + ln - 1 - j;
306→        assert a <= k <= r0;
307→        assert s[k] == c;
308→        var jIdx := j - a;
309→        var kIdx := k - a;
310→        assert jIdx + kIdx == ln - 1;
311→        assert w[kIdx] == s[k] == c;
312→        assert w[jIdx] == w[ln - 1 - jIdx] == w[kIdx];
313→        assert s[j] == w[jIdx] == c;
314→      }
315→    }
316→
317→    // Now: [a, r0] all c and [mLow, a+ln-1] all c.
318→    // mLow = 2a+ln-1-r0. Since r0 >= p = a+(ln-1)/2: mLow = 2a+ln-1-r0 <= 2a+ln-1-p = p <= r0.
319→    // So mLow <= r0. The two ranges overlap: [a, r0] and [mLow, a+ln-1] with mLow <= r0.
320→    // Their union is [a, max(r0, a+ln-1)] = [a, a+ln-1] (since a+ln-1 > r0 here).
321→    // Wait, the union of [a, r0] and [mLow, a+ln-1] where mLow <= r0:
322→    // Union = [min(a, mLow), max(r0, a+ln-1)] = [a, a+ln-1] (since a <= mLow and a+ln-1 >= r0).
323→    // But is the union contiguous? Yes, because mLow <= r0, so [a, r0] and [mLow, a+ln-1] overlap.
324→    // All positions in [a, a+ln-1] have char c!
325→    assert forall j :: a <= j <= a + ln - 1 ==> s[j] == c
326→    by {
327→      forall j | a <= j <= a + ln - 1
328→        ensures s[j] == c
329→      {
330→        if j <= r0 {
331→          assert s[j] == c;  // j in [a, r0], part of run
332→        } else {
333→          assert j >= mLow;  // j > r0 >= mLow, so j in [mLow, a+ln-1]
334→          assert s[j] == c;
335→        }
336→      }
337→    }
338→
339→    // But the run [i0, r0] is maximal: s[r0+1] != c (if r0 < |s|-1).
340→    // Position r0+1 is in [a+1, a+ln-1] (since r0 >= a and r0 < a+ln-1, so r0+1 <= a+ln-1).
341→    assert a <= r0 + 1 <= a + ln - 1;
342→    assert s[r0 + 1] == c;
343→    // Contradiction with run boundary
344→    if r0 < |s| - 1 {
345→      assert s[r0 + 1] != s[r0];
346→      assert s[r0] == c;
347→      assert false;
348→    } else {
349→      // r0 = |s| - 1, but r0 < a+ln-1 means a+ln-1 > |s|-1, i.e., a+ln > |s|. Contradiction with a+ln <= |s|.
350→      assert false;
351→    }
352→  }
353→}
354→
355→// Main coverage lemma
356→lemma {:induction false} {:resource_limit 8000000} CenterExpansionOptimal(
357→    s: seq<char>, a: int, ln: int, i0: int, r0: int, l_f: int, r_f: int)
358→  requires |s| > 0
359→  requires 0 <= a < |s| && 1 <= ln <= |s| && a + ln <= |s|
360→  requires IsPalindrome(s[a..a+ln])
361→  requires 0 <= i0 <= r0 < |s|
362→  requires i0 <= a + (ln - 1) / 2 <= r0
363→  requires forall j :: i0 <= j <= r0 ==> s[j] == s[i0]
364→  requires r0 == |s| - 1 || s[r0] != s[r0 + 1]
365→  requires i0 == 0 || s[i0 - 1] != s[i0]
366→  requires 0 <= l_f <= i0 && r0 <= r_f < |s|
367→  requires IsPalindrome(s[l_f..r_f+1])
368→  requires l_f + r_f == i0 + r0
369→  requires l_f == 0 || r_f == |s| - 1 || s[l_f - 1] != s[r_f + 1]
370→  ensures r_f - l_f + 1 >= ln
371→{
372→  if i0 >= a && r0 <= a + ln - 1 {
373→    // Case A: run contained in palindrome.
374→    RunSymmetricInPalindrome(s, a, ln, i0, r0);
375→    assert i0 + r0 == 2 * a + ln - 1;
376→
377→    // The expansion from [i0, r0] went d = i0 - l_f steps.
378→    // We need d >= i0 - a, i.e., l_f <= a.
379→    // By contradiction: if l_f > a, the expansion stopped too early.
380→    if l_f > a {
381→      // l_f > a, so d = i0 - l_f < i0 - a.
382→      // At step d+1: the expansion would check s[l_f-1] vs s[r_f+1].
383→      // By SymmetricExpansionStep with k = d+1 = i0-l_f+1:
384→      // s[i0-(d+1)] = s[l_f-1] and s[r0+(d+1)] = s[r_f+1].
385→      // These are equal. So the expansion should have continued. Contradiction with maximality.
386→      var d := i0 - l_f;
387→      assert d < i0 - a;
388→      assert d + 1 <= i0 - a;
389→      SymmetricExpansionStep(s, a, ln, i0, r0, d + 1);
390→      assert s[i0 - (d + 1)] == s[r0 + (d + 1)];
391→      assert i0 - (d + 1) == l_f - 1;
392→      assert r0 + (d + 1) == r_f + 1;
393→      // So s[l_f - 1] == s[r_f + 1]. But the expansion stopped, meaning
394→      // l_f == 0 || r_f == |s|-1 || s[l_f-1] != s[r_f+1].
395→      // l_f > a >= 0, so l_f > 0. r_f < |s|-1? r_f = r0+d. r0+d = r0+i0-l_f.
396→      // r0+i0-l_f < r0+i0-a = 2a+ln-1-a = a+ln-1 < |s|. So r_f <= a+ln-2 < |s|-1.
397→      // Wait, r_f < |s| is given. r_f = r0+d = i0+r0-l_f.
398→      assert l_f >= 1;  // l_f > a >= 0
399→      assert r_f == r0 + d;
400→      assert r_f < |s| - 1 by {
401→        assert r_f == i0 + r0 - l_f;
402→        assert i0 + r0 == 2 * a + ln - 1;
403→        assert r_f == 2 * a + ln - 1 - l_f;
404→        assert l_f >= a + 1;  // l_f > a
405→        assert r_f <= 2 * a + ln - 1 - a - 1 == a + ln - 2;
406→        assert a + ln <= |s|;
407→        assert r_f <= |s| - 2;
408→      }
409→      // So l_f != 0 and r_f != |s|-1, hence s[l_f-1] != s[r_f+1]. But we showed they're equal.
410→      assert s[l_f - 1] != s[r_f + 1];
411→      assert false;
412→    }
413→    assert l_f <= a;
414→    assert r_f == i0 + r0 - l_f >= i0 + r0 - a == 2 * a + ln - 1 - a == a + ln - 1;
415→    assert r_f - l_f + 1 >= (a + ln - 1) - a + 1 == ln;
416→
417→  } else if i0 < a {
418→    // Case B: run starts before palindrome.
419→    RunExtendsBeyondPalindrome(s, a, ln, i0, r0);
420→    assert r0 >= a + ln - 1;
421→    assert r_f >= r0 >= a + ln - 1;
422→    assert l_f <= i0 < a;
423→    assert r_f - l_f + 1 >= (a + ln - 1) - (a - 1) == ln;
424→
425→  } else {
426→    // Case C: i0 >= a and r0 > a+ln-1.
427→    if i0 == a {
428→      assert r_f >= r0 > a + ln - 1;
429→      assert l_f <= i0 == a;
430→      assert r_f - l_f + 1 >= (a + ln) - a == ln;
431→    } else {
432→      // i0 > a, r0 > a+ln-1. Derive contradiction.
433→      assert i0 > 0 by { assert i0 > a >= 0; }
434→      var w2 := s[a..a+ln];
435→      var mirrorI0minus1 := 2 * a + ln - i0;  // mirror of position i0-1
436→      // i0-1 >= a (since i0 > a means i0 >= a+1)
437→      assert i0 - 1 >= a;
438→      assert i0 - 1 < a + ln by { assert i0 <= a + (ln - 1) / 2; assert (ln - 1) / 2 < ln; }
439→      // mirror is within palindrome
440→      assert a <= mirrorI0minus1 <= a + ln - 1 by {
441→        assert mirrorI0minus1 == 2 * a + ln - i0;
442→        assert i0 >= a + 1;
443→        assert mirrorI0minus1 <= 2 * a + ln - a - 1 == a + ln - 1;
444→        assert i0 <= a + (ln - 1) / 2;
445→        assert mirrorI0minus1 >= 2 * a + ln - (a + (ln - 1) / 2);
446→        assert 2 * a + ln - (a + (ln - 1) / 2) == a + ln - (ln - 1) / 2;
447→        assert ln - (ln - 1) / 2 >= 1;
448→        assert mirrorI0minus1 >= a + 1;
449→      }
450→      // By palindrome: s[i0-1] == s[mirrorI0minus1]
451→      var idx1 := i0 - 1 - a;
452→      var idx2 := mirrorI0minus1 - a;
453→      assert idx1 + idx2 == ln - 1;
454→      assert w2[idx1] == w2[ln - 1 - idx1] == w2[idx2];
455→      assert s[i0 - 1] == w2[idx1];
456→      assert s[mirrorI0minus1] == w2[idx2];
457→      assert s[i0 - 1] == s[mirrorI0minus1];
458→      // mirrorI0minus1 is in [i0, r0] (it's >= p+1 and <= a+ln-1 < r0+1, so in [i0, r0])
459→      // Actually we need mirrorI0minus1 >= i0 and <= r0.
460→      assert mirrorI0minus1 >= i0 by {
461→        // mirrorI0minus1 = 2a+ln-i0. i0 <= a+(ln-1)/2.
462→        // 2a+ln-i0 >= 2a+ln-a-(ln-1)/2 = a+ln-(ln-1)/2 = a+(ln+1)/2.
463→        // (ln+1)/2 >= 1 for ln >= 1. And a+(ln+1)/2 >= a+1 >= i0? Not necessarily.
464→        // i0 <= a+(ln-1)/2. We need a+(ln+1)/2 >= i0, which is true since a+(ln+1)/2 >= a+(ln-1)/2 >= i0.
465→        // Actually a+(ln+1)/2 > a+(ln-1)/2 when ln is even. When ln is odd, (ln+1)/2 = (ln-1)/2+1 > (ln-1)/2.
466→        // So mirrorI0minus1 >= a+(ln+1)/2 > a+(ln-1)/2 >= i0. Wait, this might not hold exactly.
467→        // Let's be more careful: mirrorI0minus1 = 2a+ln-i0.
468→        // We need 2a+ln-i0 >= i0, i.e., 2*i0 <= 2a+ln, i.e., i0 <= a+ln/2.
469→        // i0 <= a+(ln-1)/2 <= a+ln/2. So 2*i0 <= 2a+ln-1 <= 2a+ln. Yes.
470→      }
471→      assert mirrorI0minus1 <= r0 by {
472→        assert mirrorI0minus1 <= a + ln - 1;
473→        assert r0 > a + ln - 1;
474→        assert mirrorI0minus1 < r0;
475→      }
476→      // So s[mirrorI0minus1] = c (it's in the run [i0, r0])
477→      var c := s[i0];
478→      assert s[mirrorI0minus1] == c;
479→      assert s[i0 - 1] == c;
480→      // But run boundary: s[i0-1] != s[i0] = c
481→      assert s[i0 - 1] != s[i0];
482→      assert false;
483→    }
484→  }
485→}
