487→method longest_palindromic_substring(s: seq<char>) returns (result: seq<char>)
488→  requires |s| >= 1
489→  ensures  longest_palindromic_substringPost(s, result)
490→{
491→    var n := |s|;
492→    if n == 0 {
493→        return [];
494→    }
495→
496→    var start := 0;
497→    var maxLength := 1;
498→    SingleCharIsPalindrome(s, 0);
499→
500→    var i := 0;
501→
502→    while i < n
503→      invariant 0 <= i <= n
504→      invariant 0 <= start
505→      invariant 1 <= maxLength
506→      invariant start + maxLength <= n
507→      invariant IsPalindrome(s[start..start + maxLength])
508→      invariant i == 0 || i >= n || s[i-1] != s[i]
509→      invariant forall a, ln {:trigger s[a..a+ln]} ::
510→        0 <= a < n && 1 <= ln <= n && a + ln <= n &&
511→        IsPalindrome(s[a..a+ln]) &&
512→        a + (ln - 1) / 2 < i
513→        ==> ln <= maxLength
514→    {
515→        var i0 := i;
516→        var l := i;
517→        var r := i;
518→
519→        SingleCharIsPalindrome(s, i);
520→
521→        while r < n - 1 && s[r] == s[r + 1]
522→          invariant i <= l <= r < n
523→          invariant l == i
524→          invariant IsPalindrome(s[l..r+1])
525→          invariant forall j :: l <= j <= r ==> s[j] == s[l]
526→        {
527→            assert s[r+1] == s[l];
528→            var w := s[l..r+2];
529→            assert forall j :: 0 <= j < |w| ==> w[j] == w[0]
530→            by {
531→              forall j | 0 <= j < |w| ensures w[j] == w[0]
532→              { assert w[j] == s[l+j]; assert w[0] == s[l]; }
533→            }
534→            AllEqualIsPalindrome(w);
535→            r := r + 1;
536→        }
537→
538→        var r0 := r;
539→        i := r;
540→
541→        while l > 0 && r < n - 1 && s[l - 1] == s[r + 1]
542→          invariant 0 <= l <= r < n
543→          invariant IsPalindrome(s[l..r+1])
544→          invariant l + r == i0 + r0
545→        {
546→            PalindromeExpand(s, l, r);
547→            l := l - 1;
548→            r := r + 1;
549→        }
550→
551→        var length := r - l + 1;
552→        if length > maxLength
553→        {
554→            start := l;
555→            maxLength := length;
556→        }
557→
558→        // Prove coverage for palindromes with midpoint in [i0, r0]
559→        forall a, ln {:trigger s[a..a+ln]} |
560→          0 <= a < n && 1 <= ln <= n && a + ln <= n &&
561→          IsPalindrome(s[a..a+ln]) &&
562→          i0 <= a + (ln - 1) / 2 <= r0
563→          ensures ln <= length
564→        {
565→          CenterExpansionOptimal(s, a, ln, i0, r0, l, r);
566→        }
567→
568→        i := i + 1;
569→    }
570→
571→    result := s[start..start + maxLength];
572→    assert IsPalindrome(result);
573→    assert SubstringAt(s, result, start);
574→    assert IsSubstring(s, result) by {
575→      assert 0 <= start <= n - maxLength;
576→    }
577→
578→    forall a, ln | 0 <= a < |s| && 0 <= ln <= |s| && PalindromicSubstringAt(s, a, ln)
579→      ensures ln <= |result|
580→    {
581→      if ln >= 1 {
582→        assert a + ln <= n;
583→        assert IsPalindrome(s[a..a+ln]);
584→        var mid := a + (ln - 1) / 2;
585→        assert 0 <= mid < n;
586→        assert mid < i;
587→      }
588→    }
589→}
